function sliderPhoto() {
    var swiper = new Swiper('.photo .mySwiper', {
        slidesPerView: 2,
        spaceBetween: 24,
        speed: 500,
        breakpoints: {
            320: {
                slidesPerView: 1.2,
                spaceBetween: 12,
            },
            768: {
                slidesPerView: 2.35,
                spaceBetween: 12,
            },
            993: {
                slidesPerView: 2.35,
                spaceBetween: 24,
            },
            1601: {
                slidesPerView: 2,
                spaceBetween: 24,
            }
        }
    })
}

function sliderProjects() {
    var swiper = new Swiper('.projects .mySwiper', {
        slidesPerView: 2,
        spaceBetween: 24,
        speed: 500,
        navigation: {
            nextEl: ".projects .swiper-button-next",
            prevEl: ".projects .swiper-button-prev",
        },
        breakpoints: {
            320: {
                slidesPerView: 1,
                spaceBetween: 12,
            },
            577: {
                slidesPerView: 1.5,
                spaceBetween: 12,
            },
            768: {
                slidesPerView: 2,
                spaceBetween: 12,
            },
            993: {
                slidesPerView: 2,
                spaceBetween: 24,
            }
        }
    })
}

$(document).ready(function () {
  sliderPhoto();
  sliderProjects();

    // Tabs
    $(".tab").click(function () {
        let path = $(this).attr("data-tab-path")
        $(this).siblings(".tab").removeClass("tab--active")
        $(this).addClass("tab--active")

        $(this).parents(".tabs-inner").find(".tab__content").removeClass("tab__content--active")
        $(this).parents(".tabs-inner").find(`.tab__content[data-content-path="${path}"]`).addClass("tab__content--active")
    })

    // Tabs--modal
    $(".tab-modal").click(function () {
        let path = $(this).attr("data-tab-path")
        $(this).siblings(".tab-modal").removeClass("tab-modal--active")
        $(this).addClass("tab-modal--active")

        $(this).parents(".wrapper").find(".tab-modal__content").removeClass("tab-modal__content--active")
        $(this).parents(".wrapper").find(`.tab-modal__content[data-content-path="${path}"]`).addClass("tab-modal__content--active")
    })

    // Modal
    $("[data-modal]").click(function () {
        let modalId = $(this).attr("data-modal")

        openModal(modalId)
    })

    function openModal(modalId){
        $(`#${modalId}`).addClass("modal--active")
        $("body").addClass("fixed-body")
    }

    $(".modal").click(function () {
        closeModal()
    })

    $("._close-modal").click(function () {
        closeModal()
    })

    $(".modal__dialog").click(function (e) {
        e.stopPropagation()
    })

    function closeModal() {
        $('.modal--active video').each(function () {
            this.pause();
            this.currentTime = 0;
        });

        $('.modal').removeClass("modal--active")
        $("body").removeClass("fixed-body")
    }


})

 // Zoom
    if (window.innerWidth <= 992) {
        if (window.innerWidth <= 992) {
  const box = document.querySelector('.infrastructure__img');
  const img = box.querySelector('img');

  let scale = 1;

  let startDist = 0;

  let pointX = 0;
  let pointY = 0;

  let startX = 0;
  let startY = 0;

  let isDragging = false;

  function updateTransform() {
    img.style.transform =
      `translate(${pointX}px, ${pointY}px) scale(${scale})`;
  }

  function getDistance(touches) {
    const dx = touches[0].clientX - touches[1].clientX;
    const dy = touches[0].clientY - touches[1].clientY;

    return Math.sqrt(dx * dx + dy * dy);
  }

  // START
  box.addEventListener('touchstart', (e) => {

    // pinch zoom
    if (e.touches.length === 2) {
      startDist = getDistance(e.touches);
    }

    // drag
    if (e.touches.length === 1 && scale > 1) {
      isDragging = true;

      startX = e.touches[0].clientX - pointX;
      startY = e.touches[0].clientY - pointY;
    }

  }, { passive: false });

  // MOVE
  box.addEventListener('touchmove', (e) => {

    // PINCH
    if (e.touches.length === 2) {
      e.preventDefault();

      const newDist = getDistance(e.touches);

      const delta = newDist / startDist;

      scale = Math.min(Math.max(scale * delta, 1), 4);

      updateTransform();

      startDist = newDist;
    }

    // DRAG
    if (e.touches.length === 1 && isDragging && scale > 1) {
      e.preventDefault();

      pointX = e.touches[0].clientX - startX;
      pointY = e.touches[0].clientY - startY;

      updateTransform();
    }

  }, { passive: false });

  // END
  box.addEventListener('touchend', () => {

    isDragging = false;

    // сброс позиции при полном уменьшении
    if (scale <= 1) {
      scale = 1;
      pointX = 0;
      pointY = 0;

      updateTransform();
    }

  });

  // плавность
  img.style.transition = 'transform 0.05s linear';
}
    }
